     1→/**
     2→ * Unit Tests for Audit Trail Failure Recovery (T091 HP-3)
     3→ *
     4→ * Tests validate the hybrid progressive recording approach's failure resilience:
     5→ * - Partial trace preservation when pipeline crashes mid-execution
     6→ * - Error context captured for debugging
     7→ * - Stage failure detection accuracy
     8→ * - Graceful handling of crashes at different pipeline stages
     9→ *
    10→ * This validates the core value proposition of the hybrid approach:
    11→ * "If pipeline crashes at stage 5, stages 1-4 are already recorded"
    12→ */
    13→
    14→import { AuditTrailGenerator } from '../../src/audit-trail/audit-trail-generator';
    15→import { ClassificationResult } from '../../src/types/classification-result';
    16→import { ClassificationSession } from '../../src/types/classification-session';
    17→import { CategoryConfiguration } from '../../src/types/category-configuration';
    18→import { StageName } from '../../src/types/stage-name';
    19→import { ExplainabilityTrace } from '../../src/types/explainability-trace';
    20→
    21→describe('Audit Trail Failure Recovery (T091 HP-3)', () => {
    22→  // Mock minimal config for audit trail generator
    23→  // Using 'as unknown as CategoryConfiguration' to bypass strict type checking for test simplicity
    24→  const mockConfig = {
    25→    processingConfig: {
    26→      settings: {
    27→        multiLabelSelection: {
    28→          maxLabels: 3,
    29→          highConfidenceThreshold: 15,
    30→          mediumConfidenceThreshold: 10,
    31→          lowConfidenceThreshold: 5,
    32→          secondaryLabelMinGap: 3,
    33→          allowedCombinations: [],
    34→          strictCombinationMode: false,
    35→        },
    36→        disambiguation: {
    37→          pairwiseAdjustments: true,
    38→          confidenceGapThreshold: 2,
    39→        },
    40→      },
    41→      categorySignals: {},
    42→      attributes: {
    43→        derived: {},
    44→        schema: {},
    45→        detectors: [],
    46→        attributeBonusMap: {},
    47→      },
    48→      ai: {
    49→        enabled: true,
    50→        providers: [],
    51→        prompts: {},
    52→        schemas: {},
    53→      },
    54→    },
    55→    domainSources: {},
    56→  } as unknown as CategoryConfiguration;
    57→
    58→  const mockSession: ClassificationSession = {
    59→    id: 'session-test-123',
    60→    startedAt: new Date('2025-10-20T10:00:00Z'),
    61→    emailCount: 1,
    62→    successCount: 0,
    63→    errorCount: 0,
    64→    processingMode: 'sequential',
    65→    batchSize: 1,
    66→    performanceMetrics: {
    67→      totalDurationMs: 0,
    68→      avgEmailDurationMs: 0,
    69→      parallelStagesCount: 0,
    70→      databaseBatchOps: 0,
    71→    },
    72→    configVersion: 'test-v1',
    73→    configSnapshot: {},
    74→    errors: [],
    75→    warnings: [],
    76→  };
    77→
    78→  /**
    79→   * Helper to create a classification result with initialized explainability trace
    80→   */
    81→  function createTestResult(emailId: string, sessionId: string): ClassificationResult {
    82→    const explainabilityTrace: ExplainabilityTrace = {
    83→      sessionId,
    84→      emailId,
    85→      hardAssertions: [],
    86→      strongIndicators: [],
    87→      ruleScoring: [],
    88→      attributeDetection: [],
    89→      attributeInfluence: [],
    90→      disambiguation: [],
    91→      multiLabelSelection: [],
    92→      aiRouting: undefined,
    93→      stageTimings: {},
    94→      configurationRefs: {},
    95→      parallelExecutionMap: {},
    96→      alternativeCategories: [],
    97→      finalDecisionReason: '',
    98→    };
    99→
   100→    return {
   101→      id: emailId,
   102→      emailId,
   103→      sessionId,
   104→      primaryCategory: '',
   105→      subtype: null,
   106→      secondaryCategories: [],
   107→      confidence: 0,
   108→      processingDurationMs: 0,
   109→      processedAt: new Date(),
   110→      selectedLabels: [],
   111→      candidateScores: {},
   112→      needsAiClassification: false,
   113→      aiRoutingUsed: false,
   114→      scoreBreakdown: {
   115→        emailId,
   116→        categoryScores: {},
   117→        stageContributions: [],
   118→        disambiguationApplied: false,
   119→        parallelComputationMetrics: { batchSize: 0, computationTimeMs: 0 },
   120→      },
   121→      attributeContext: {
   122→        emailId,
   123→        urgency: 'none',
   124→        domains: [],
   125→        structuralPatterns: [],
   126→        detectedInParallel: false,
   127→        attributeInfluences: [],
   128→        derivedAttributes: {},
   129→        detectionConfidence: {},
   130→        detectionSources: {},
   131→      },
   132→      explainabilityTrace,
   133→      determinedActions: [],
   134→      classificationMethod: 'rule-based',
   135→      finalClassificationSummary: undefined,
   136→    };
   137→  }
   138→
   139→  describe('Progressive Recording Resilience', () => {
   140→    it('should preserve partial trace when pipeline fails after stage 1 (hardAssertions)', () => {
   141→      const generator = new AuditTrailGenerator(mockConfig);
   142→      const result = createTestResult('email-123', mockSession.id);
   143→
   144→      // Simulate stage 1 completing successfully
   145→      result.explainabilityTrace.hardAssertions = [
   146→        {
   147→          category: 'financial',
   148→          assertionType: 'fromDomain',
   149→          matchedValue: 'chase.com',
   150→          confidence: 'HIGH_CONFIDENCE',
   151→          triggered: true,
   152→          reason: 'Domain matched hard assertion',
   153→        },
   154→      ];
   155→      result.explainabilityTrace.stageTimings.hardAssertions = 5;
   156→
   157→      // Record stage 1
   158→      generator.recordStage('hardAssertions', result, mockSession);
   159→
   160→      // Simulate pipeline crash before stage 2
   161→      const error = new Error('Network timeout in stage 2');
   162→      generator.recordFailure(result, mockSession, error);
   163→
   164→      // Verify partial trace preserved
   165→      expect(result.explainabilityTrace.hardAssertions).toHaveLength(1);
   166→      expect(result.explainabilityTrace.hardAssertions[0].category).toBe('financial');
   167→
   168→      // Verify error context captured
   169→      const trace = result.explainabilityTrace as unknown as Record<string, unknown>;
   170→      expect(trace.partialResults).toBe(true);
   171→      expect(trace.errorMessage).toBe('Network timeout in stage 2');
   172→      expect(trace.errorStack).toBeDefined();
   173→      expect(trace.failedStage).toContain('strongIndicators');
   174→    });
   175→
   176→    it('should preserve partial trace when pipeline fails after stage 4 (attributeDetection)', () => {
   177→      const generator = new AuditTrailGenerator(mockConfig);
   178→      const result = createTestResult('email-456', mockSession.id);
   179→
   180→      // Simulate stages 1-4 completing successfully
   181→      result.explainabilityTrace.hardAssertions = [];
   182→      result.explainabilityTrace.stageTimings.hardAssertions = 5;
   183→      generator.recordStage('hardAssertions', result, mockSession);
   184→
   185→      result.explainabilityTrace.strongIndicators = [
   186→        {
   187→          category: 'financial',
   188→          indicatorType: 'subjectContains',
   189→          matchedValue: 'invoice',
   190→          seedScore: 10,
   191→          diminishingReturnsApplied: false,
   192→          existingSeedScore: 0,
   193→          finalSeedScore: 10,
   194→          reason: 'Subject keyword match',
   195→        },
   196→      ];
   197→      result.explainabilityTrace.stageTimings.strongIndicators = 8;
   198→      generator.recordStage('strongIndicators', result, mockSession);
   199→
   200→      result.explainabilityTrace.ruleScoring = [
   201→        {
   202→          categoryCode: 'financial',
   203→          aggregatedScore: 12,
   204→          subtypeScores: {},
   205→          ruleMatches: [],
   206→          scoringRationale: ['High tier rule match'],
   207→          selectedSubtypeId: 'invoice',
   208→          confidence: 0.85,
   209→        },
   210→      ];
   211→      result.explainabilityTrace.stageTimings.ruleScoring = 45;
   212→      generator.recordStage('ruleScoring', result, mockSession);
   213→
   214→      result.explainabilityTrace.attributeDetection = [
   215→        {
   216→          attribute: 'hasAmount',
   217→          detected: true,
   218→          detectionMethod: 'direct',
   219→          sourceField: 'body',
   220→          confidence: 0.95,
   221→          parallelProcessed: false,
   222→          dependencies: [],
   223→          reason: 'Amount pattern detected',
   224→        },
   225→      ];
   226→      result.explainabilityTrace.stageTimings.attributeDetection = 20;
   227→      generator.recordStage('attributeDetection', result, mockSession);
   228→
   229→      // Simulate pipeline crash before stage 5
   230→      const error = new Error('OOM error in attribute influence stage');
   231→      generator.recordFailure(result, mockSession, error);
   232→
   233→      // Verify stages 1-4 preserved
   234→      expect(result.explainabilityTrace.hardAssertions).toEqual([]);
   235→      expect(result.explainabilityTrace.strongIndicators).toHaveLength(1);
   236→      expect(result.explainabilityTrace.ruleScoring).toHaveLength(1);
   237→      expect(result.explainabilityTrace.attributeDetection).toHaveLength(1);
   238→
   239→      // Verify stage 5+ not present
   240→      expect(result.explainabilityTrace.attributeInfluence).toEqual([]);
   241→      expect(result.explainabilityTrace.disambiguation).toEqual([]);
   242→
   243→      // Verify error context and failed stage detection
   244→      const trace = result.explainabilityTrace as unknown as Record<string, unknown>;
   245→      expect(trace.partialResults).toBe(true);
   246→      expect(trace.errorMessage).toContain('OOM error');
   247→      expect(trace.failedStage).toContain('attributeInfluence');
   248→    });
   249→
   250→    it('should preserve partial trace when pipeline fails after stage 7 (multiLabelSelection)', () => {
   251→      const generator = new AuditTrailGenerator(mockConfig);
   252→      const result = createTestResult('email-789', mockSession.id);
   253→
   254→      // Simulate stages 1-7 completing successfully
   255→      const stages: StageName[] = [
   256→        'hardAssertions',
   257→        'strongIndicators',
   258→        'ruleScoring',
   259→        'attributeDetection',
   260→        'attributeInfluence',
   261→        'disambiguation',
   262→        'multiLabelSelection',
   263→      ];
   264→
   265→      for (const stage of stages) {
   266→        // Set mock data based on stage
   267→        switch (stage) {
   268→          case 'hardAssertions':
   269→            result.explainabilityTrace.hardAssertions = [];
   270→            break;
   271→          case 'strongIndicators':
   272→            result.explainabilityTrace.strongIndicators = [];
   273→            break;
   274→          case 'ruleScoring':
   275→            result.explainabilityTrace.ruleScoring = [];
   276→            break;
   277→          case 'attributeDetection':
   278→            result.explainabilityTrace.attributeDetection = [];
   279→            break;
   280→          case 'attributeInfluence':
   281→            result.explainabilityTrace.attributeInfluence = [];
   282→            break;
   283→          case 'disambiguation':
   284→            result.explainabilityTrace.disambiguation = [];
   285→            break;
   286→          case 'multiLabelSelection':
   287→            result.explainabilityTrace.multiLabelSelection = [
   288→              {
   289→                selectedCategories: ['financial'],
   290→                rejectedCategories: [],
   291→                coPresenceRulesApplied: [],
   292→                maxLabelsLimit: 3,
   293→                minSecondaryConfidence: 0.5,
   294→                reason: 'High confidence',
   295→              },
   296→            ];
   297→            break;
   298→        }
   299→
   300→        result.explainabilityTrace.stageTimings[stage] = 10;
   301→        generator.recordStage(stage, result, mockSession);
   302→      }
   303→
   304→      // Simulate pipeline crash in AI pipeline (stage 8)
   305→      const error = new Error('OpenAI API rate limit exceeded');
   306→      generator.recordFailure(result, mockSession, error);
   307→
   308→      // Verify stages 1-7 fully preserved
   309→      expect(result.explainabilityTrace.multiLabelSelection).toHaveLength(1);
   310→      expect(result.explainabilityTrace.stageTimings).toHaveProperty('multiLabelSelection');
   311→
   312→      // Verify AI stages not present
   313→      expect(result.explainabilityTrace.aiRouting).toBeUndefined();
   314→
   315→      // Verify error context
   316→      const trace = result.explainabilityTrace as unknown as Record<string, unknown>;
   317→      expect(trace.partialResults).toBe(true);
   318→      expect(trace.errorMessage).toContain('OpenAI API rate limit');
   319→      expect(trace.failedStage).toContain('aiPipeline');
   320→    });
   321→  });
   322→
   323→  describe('Error Context Capture', () => {
   324→    it('should capture error message, stack, and failed stage information', () => {
   325→      const generator = new AuditTrailGenerator(mockConfig);
   326→      const result = createTestResult('email-error-001', mockSession.id);
   327→
   328→      // Record stage 1 only
   329→      result.explainabilityTrace.hardAssertions = [];
   330→      generator.recordStage('hardAssertions', result, mockSession);
   331→
   332→      // Create error with stack trace
   333→      const error = new Error('Database connection refused');
   334→      error.stack = 'Error: Database connection refused\n  at Stage2.execute (strong-indicators.ts:45)';
   335→
   336→      generator.recordFailure(result, mockSession, error);
   337→
   338→      // Verify error context
   339→      const trace = result.explainabilityTrace as unknown as Record<string, unknown>;
   340→      expect(trace.errorMessage).toBe('Database connection refused');
   341→      expect(trace.errorStack).toContain('strong-indicators.ts:45');
   342→      expect(trace.partialResults).toBe(true);
   343→      expect(trace.failedStage).toBeDefined();
   344→    });
   345→
   346→    it('should handle errors without stack traces gracefully', () => {
   347→      const generator = new AuditTrailGenerator(mockConfig);
   348→      const result = createTestResult('email-error-002', mockSession.id);
   349→
   350→      // Record a few stages
   351→      result.explainabilityTrace.hardAssertions = [];
   352→      generator.recordStage('hardAssertions', result, mockSession);
   353→
   354→      result.explainabilityTrace.strongIndicators = [];
   355→      generator.recordStage('strongIndicators', result, mockSession);
   356→
   357→      // Create error without stack trace
   358→      const error = new Error('Unknown error');
   359→      error.stack = undefined;
   360→
   361→      generator.recordFailure(result, mockSession, error);
   362→
   363→      // Verify error context (should not crash)
   364→      const trace = result.explainabilityTrace as unknown as Record<string, unknown>;
   365→      expect(trace.errorMessage).toBe('Unknown error');
   366→      expect(trace.errorStack).toBeUndefined();
   367→      expect(trace.partialResults).toBe(true);
   368→    });
   369→  });
   370→
   371→  describe('Failed Stage Detection', () => {
   372→    it('should correctly identify failed stage when crash happens at initialization', () => {
   373→      const generator = new AuditTrailGenerator(mockConfig);
   374→      const result = createTestResult('email-init-fail', mockSession.id);
   375→
   376→      // No stages recorded - crash before stage 1
   377→      const error = new Error('Configuration validation failed');
   378→      generator.recordFailure(result, mockSession, error);
   379→
   380→      const trace = result.explainabilityTrace as unknown as Record<string, unknown>;
   381→      // When no stages recorded, the failed stage is the first one (hardAssertions)
   382→      // The improved logic returns just the stage name, not "(initialization failure)" suffix
   383→      expect(trace.failedStage).toBe('hardAssertions');
   384→    });
   385→
   386→    it('should correctly identify failed stage between stages 2 and 3', () => {
   387→      const generator = new AuditTrailGenerator(mockConfig);
   388→      const result = createTestResult('email-stage23-fail', mockSession.id);
   389→
   390→      // Stages 1-2 complete
   391→      result.explainabilityTrace.hardAssertions = [];
   392→      generator.recordStage('hardAssertions', result, mockSession);
   393→
   394→      result.explainabilityTrace.strongIndicators = [];
   395→      generator.recordStage('strongIndicators', result, mockSession);
   396→
   397→      // Crash before stage 3
   398→      const error = new Error('Rule scoring failed');
   399→      generator.recordFailure(result, mockSession, error);
   400→
   401→      const trace = result.explainabilityTrace as unknown as Record<string, unknown>;
   402→      expect(trace.failedStage).toBe('ruleScoring');
   403→    });
   404→
   405→    it('should correctly identify failed stage at the end of pipeline (actionDetermination)', () => {
   406→      const generator = new AuditTrailGenerator(mockConfig);
   407→      const result = createTestResult('email-final-fail', mockSession.id);
   408→
   409→      // All stages except actionDetermination complete
   410→      const stages: StageName[] = [
   411→        'hardAssertions',
   412→        'strongIndicators',
   413→        'ruleScoring',
   414→        'attributeDetection',
   415→        'attributeInfluence',
   416→        'disambiguation',
   417→        'multiLabelSelection',
   418→      ];
   419→
   420→      for (const stage of stages) {
   421→        // Initialize empty arrays for array stages
   422→        switch (stage) {
   423→          case 'hardAssertions':
   424→            result.explainabilityTrace.hardAssertions = [];
   425→            break;
   426→          case 'strongIndicators':
   427→            result.explainabilityTrace.strongIndicators = [];
   428→            break;
   429→          case 'ruleScoring':
   430→            result.explainabilityTrace.ruleScoring = [];
   431→            break;
   432→          case 'attributeDetection':
   433→            result.explainabilityTrace.attributeDetection = [];
   434→            break;
   435→          case 'attributeInfluence':
   436→            result.explainabilityTrace.attributeInfluence = [];
   437→            break;
   438→          case 'disambiguation':
   439→            result.explainabilityTrace.disambiguation = [];
   440→            break;
   441→          case 'multiLabelSelection':
   442→            result.explainabilityTrace.multiLabelSelection = [];
   443→            break;
   444→        }
   445→        generator.recordStage(stage, result, mockSession);
   446→      }
   447→
   448→      // AI pipeline completed (optional stage)
   449→      result.explainabilityTrace.aiRouting = {
   450→        routingDecision: 'skipAi',
   451→        highConfidenceThreshold: 15,
   452→        aiRequiredThreshold: 3,
   453→        skipConditions: ['highConfidence'],
   454→        reason: 'High confidence, AI not needed',
   455→      };
   456→      result.aiRoutingUsed = false;
   457→      generator.recordStage('aiPipeline', result, mockSession);
   458→
   459→      // Crash in actionDetermination
   460→      const error = new Error('Action determination failed');
   461→      generator.recordFailure(result, mockSession, error);
   462→
   463→      const trace = result.explainabilityTrace as unknown as Record<string, unknown>;
   464→      expect(trace.failedStage).toBe('actionDetermination');
   465→    });
   466→  });
   467→
   468→  describe('Integration with finalize()', () => {
   469→    it('should allow finalize() to be called after recordFailure() without errors', () => {
   470→      const generator = new AuditTrailGenerator(mockConfig);
   471→      const result = createTestResult('email-finalize-after-fail', mockSession.id);
   472→
   473→      // Record some stages
   474→      result.explainabilityTrace.hardAssertions = [];
   475→      generator.recordStage('hardAssertions', result, mockSession);
   476→
   477→      result.explainabilityTrace.strongIndicators = [];
   478→      generator.recordStage('strongIndicators', result, mockSession);
   479→
   480→      // Record failure
   481→      const error = new Error('Simulated failure');
   482→      generator.recordFailure(result, mockSession, error);
   483→
   484→      // Attempting to finalize after failure should not crash
   485→      // (This might happen in error recovery scenarios)
   486→      expect(() => {
   487→        try {
   488→          generator.finalize(result, mockSession);
   489→        } catch (e) {
   490→          // Finalize might throw due to missing required stages,
   491→          // but should not crash with unhandled exceptions
   492→          expect(e).toBeInstanceOf(Error);
   493→        }
   494→      }).not.toThrow();
   495→    });
   496→
   497→    it('should not lose partial trace data when finalize() is attempted after failure', () => {
   498→      const generator = new AuditTrailGenerator(mockConfig);
   499→      const result = createTestResult('email-preserve-after-finalize', mockSession.id);
   500→
   501→      // Record stages 1-3
   502→      result.explainabilityTrace.hardAssertions = [
   503→        {
   504→          category: 'financial',
   505→          assertionType: 'fromDomain',
   506→          matchedValue: 'chase.com',
   507→          confidence: 'HIGH_CONFIDENCE',
   508→          triggered: true,
   509→          reason: 'Domain match',
   510→        },
   511→      ];
   512→      generator.recordStage('hardAssertions', result, mockSession);
   513→
   514→      result.explainabilityTrace.strongIndicators = [];
   515→      generator.recordStage('strongIndicators', result, mockSession);
   516→
   517→      result.explainabilityTrace.ruleScoring = [];
   518→      generator.recordStage('ruleScoring', result, mockSession);
   519→
   520→      // Record failure
   521→      const error = new Error('Stage 4 crashed');
   522→      generator.recordFailure(result, mockSession, error);
   523→
   524→      // Attempt finalize (will fail due to missing stages, but partial trace should remain)
   525→      try {
   526→        generator.finalize(result, mockSession);
   527→      } catch {
   528→        // Expected to throw due to incomplete trace
   529→      }
   530→
   531→      // Verify partial trace data still intact
   532→      expect(result.explainabilityTrace.hardAssertions).toHaveLength(1);
   533→      expect(result.explainabilityTrace.strongIndicators).toEqual([]);
   534→      expect(result.explainabilityTrace.ruleScoring).toEqual([]);
   535→
   536→      const trace = result.explainabilityTrace as unknown as Record<string, unknown>;
   537→      expect(trace.partialResults).toBe(true);
   538→      expect(trace.errorMessage).toBe('Stage 4 crashed');
   539→    });
   540→  });
