   542→  describe('Real-World Failure Scenarios', () => {
   543→    it('should handle memory exhaustion failure mid-pipeline', () => {
   544→      const generator = new AuditTrailGenerator(mockConfig);
   545→      const result = createTestResult('email-memory-fail', mockSession.id);
   546→
   547→      // Stages 1-5 complete
   548→      result.explainabilityTrace.hardAssertions = [];
   549→      generator.recordStage('hardAssertions', result, mockSession);
   550→
   551→      result.explainabilityTrace.strongIndicators = [];
   552→      generator.recordStage('strongIndicators', result, mockSession);
   553→
   554→      result.explainabilityTrace.ruleScoring = [];
   555→      generator.recordStage('ruleScoring', result, mockSession);
   556→
   557→      result.explainabilityTrace.attributeDetection = [];
   558→      generator.recordStage('attributeDetection', result, mockSession);
   559→
   560→      result.explainabilityTrace.attributeInfluence = [];
   561→      generator.recordStage('attributeInfluence', result, mockSession);
   562→
   563→      // Memory exhaustion in disambiguation
   564→      const error = new Error('JavaScript heap out of memory');
   565→      error.name = 'RangeError';
   566→      generator.recordFailure(result, mockSession, error);
   567→
   568→      // Verify stages 1-5 intact
   569→      expect(result.explainabilityTrace.attributeInfluence).toEqual([]);
   570→
   571→      const trace = result.explainabilityTrace as unknown as Record<string, unknown>;
   572→      expect(trace.errorMessage).toContain('heap out of memory');
   573→      expect(trace.failedStage).toBe('disambiguation');
   574→    });
   575→
   576→    it('should handle external API timeout in AI pipeline', () => {
   577→      const generator = new AuditTrailGenerator(mockConfig);
   578→      const result = createTestResult('email-api-timeout', mockSession.id);
   579→
   580→      // All rule-based stages complete (1-7)
   581→      const stages: StageName[] = [
   582→        'hardAssertions',
   583→        'strongIndicators',
   584→        'ruleScoring',
   585→        'attributeDetection',
   586→        'attributeInfluence',
   587→        'disambiguation',
   588→        'multiLabelSelection',
   589→      ];
   590→
   591→      for (const stage of stages) {
   592→        switch (stage) {
   593→          case 'hardAssertions':
   594→            result.explainabilityTrace.hardAssertions = [];
   595→            break;
   596→          case 'strongIndicators':
   597→            result.explainabilityTrace.strongIndicators = [];
   598→            break;
   599→          case 'ruleScoring':
   600→            result.explainabilityTrace.ruleScoring = [];
   601→            break;
   602→          case 'attributeDetection':
   603→            result.explainabilityTrace.attributeDetection = [];
   604→            break;
   605→          case 'attributeInfluence':
   606→            result.explainabilityTrace.attributeInfluence = [];
   607→            break;
   608→          case 'disambiguation':
   609→            result.explainabilityTrace.disambiguation = [];
   610→            break;
   611→          case 'multiLabelSelection':
